UPDATE [dbo].TB_FS_ESTMATE
   SET EST_USE_YN    = #{est_use_yn}
     , EST_CHG_DATE  = GETDATE()
     , STATUS        = #{status}
     , MDFR_ID       = #{mdfr_id}
     , MDFR_DT       = GETDATE()
     , EST_CHG_ID    = #{est_chg_id}
 WHERE STATUS        = 'Y'
   AND EST_USE_YN    = 'Y'
   AND SYS_ID        = #{sys_id}
   AND FS_NO         = #{fs_no}
   AND FS_SEQ        = #{fs_seq}
   AND EST_SEQ       = #{est_seq}

