INSERT INTO [dbo].TB_FS_ESTMATE
SELECT SYS_ID
     , FS_NO
     , FS_SEQ
     , [dbo].FN_FS_GETSEQUENCE('TB_FS_ESTMATE', SYS_ID, FS_NO + TRIM(CONVERT(VARCHAR(3), FS_SEQ)))
     , CST_ID
     , EST_TP_CD
     , 'Y'
     , #{est_amt}
     , NULL
     , NULL
     , 'N'
     , 'Y'
     , #{rgstr_id}
     , GETDATE()
     , #{mdfr_id}
     , GETDATE()
     , #{est_ssmm}
     , NULL
  FROM [dbo].TB_FS_ESTMATE
 WHERE STATUS        = 'N'
   AND EST_USE_YN    = 'N'
   AND SYS_ID        = #{sys_id}
   AND FS_NO         = #{fs_no}
   AND FS_SEQ        = #{fs_seq}
   AND EST_SEQ       = #{est_seq}

